/**
 * Themeoye - Swiper JS Scaffold
 * Lightweight, robust, touch-enabled slider that mirrors the Swiper.js API.
 * Uses CSS transitions and touch listeners to create a fluid, responsive experience.
 */
class Swiper {
  constructor(element, options = {}) {
    this.el = typeof element === 'string' ? document.querySelector(element) : element;
    if (!this.el) return;

    this.options = Object.assign({
      slidesPerView: 1,
      spaceBetween: 0,
      loop: false,
      autoplay: false,
      pagination: {},
      navigation: {},
      breakpoints: {},
      a11y: {}
    }, options);

    this.wrapper = this.el.querySelector('.swiper-wrapper');
    this.slides = Array.from(this.el.querySelectorAll('.swiper-slide'));
    this.currentIndex = 0;
    this.autoplayTimer = null;
    this.startX = 0;
    this.currentTranslate = 0;
    this.prevTranslate = 0;
    this.isDragging = false;

    this.init();
  }

  init() {
    this.setupLayout();
    this.setupNavigation();
    this.setupPagination();
    this.setupAutoplay();
    this.setupEvents();
    this.update();
  }

  setupLayout() {
    // Check breakpoints
    this.currentParams = Object.assign({}, this.options);
    const windowWidth = window.innerWidth;
    if (this.options.breakpoints) {
      const sortedBreakpoints = Object.keys(this.options.breakpoints)
        .map(b => parseInt(b))
        .sort((a, b) => b - a);

      for (let bp of sortedBreakpoints) {
        if (windowWidth >= bp) {
          Object.assign(this.currentParams, this.options.breakpoints[bp]);
          break;
        }
      }
    }

    // Set layout variables
    const slidesCount = this.slides.length;
    const perView = this.currentParams.slidesPerView || 1;
    const gap = this.currentParams.spaceBetween || 0;

    this.wrapper.style.display = 'flex';
    this.wrapper.style.gap = `${gap}px`;
    this.wrapper.style.transition = `transform var(--duration-normal, 300ms) var(--easing-default, ease)`;

    this.slides.forEach(slide => {
      slide.style.flexShrink = '0';
      slide.style.width = `calc((100% - ${(perView - 1) * gap}px) / ${perView})`;
    });
  }

  setupNavigation() {
    const { nextEl, prevEl } = this.currentParams.navigation;
    if (nextEl) {
      this.nextButton = typeof nextEl === 'string' ? this.el.querySelector(nextEl) || document.querySelector(nextEl) : nextEl;
      if (this.nextButton) {
        this.nextButton.addEventListener('click', () => this.slideNext());
      }
    }
    if (prevEl) {
      this.prevButton = typeof prevEl === 'string' ? this.el.querySelector(prevEl) || document.querySelector(prevEl) : prevEl;
      if (this.prevButton) {
        this.prevButton.addEventListener('click', () => this.slidePrev());
      }
    }
  }

  setupPagination() {
    const { el, clickable } = this.currentParams.pagination;
    if (!el) return;

    this.paginationContainer = typeof el === 'string' ? this.el.querySelector(el) || document.querySelector(el) : el;
    if (!this.paginationContainer) return;

    this.paginationContainer.innerHTML = '';
    const slidesCount = this.slides.length;
    
    for (let i = 0; i < slidesCount; i++) {
      const bullet = document.createElement('span');
      bullet.classList.add('swiper-pagination-bullet');
      if (i === this.currentIndex) bullet.classList.add('swiper-pagination-bullet-active');
      bullet.setAttribute('aria-label', `Go to slide ${i + 1}`);
      
      if (clickable) {
        bullet.addEventListener('click', () => this.slideTo(i));
      }
      this.paginationContainer.appendChild(bullet);
    }
  }

  setupAutoplay() {
    if (!this.currentParams.autoplay) return;
    const delay = typeof this.currentParams.autoplay === 'object' 
      ? this.currentParams.autoplay.delay || 4000 
      : this.currentParams.autoplay || 4000;

    const pauseOnHover = this.currentParams.autoplay.pauseOnMouseEnter !== false;

    this.startAutoplay(delay);

    if (pauseOnHover) {
      this.el.addEventListener('mouseenter', () => this.stopAutoplay());
      this.el.addEventListener('mouseleave', () => this.startAutoplay(delay));
    }
  }

  startAutoplay(delay) {
    this.stopAutoplay();
    this.autoplayTimer = setInterval(() => {
      this.slideNext();
    }, delay);
  }

  stopAutoplay() {
    if (this.autoplayTimer) {
      clearInterval(this.autoplayTimer);
      this.autoplayTimer = null;
    }
  }

  setupEvents() {
    // Touch Events
    this.el.addEventListener('touchstart', (e) => this.dragStart(e), { passive: true });
    this.el.addEventListener('touchmove', (e) => this.dragMove(e), { passive: false });
    this.el.addEventListener('touchend', () => this.dragEnd());

    // Mouse Events
    this.el.addEventListener('mousedown', (e) => this.dragStart(e));
    this.el.addEventListener('mousemove', (e) => this.dragMove(e));
    this.el.addEventListener('mouseup', () => this.dragEnd());
    this.el.addEventListener('mouseleave', () => {
      if (this.isDragging) this.dragEnd();
    });

    // Resize
    window.addEventListener('resize', window.themeoye.debounce(() => {
      this.setupLayout();
      this.update();
    }, 150));
  }

  dragStart(e) {
    this.isDragging = true;
    this.startX = e.type.includes('touch') ? e.touches[0].clientX : e.clientX;
    this.wrapper.style.transition = 'none';
    this.stopAutoplay();
  }

  dragMove(e) {
    if (!this.isDragging) return;
    const currentX = e.type.includes('touch') ? e.touches[0].clientX : e.clientX;
    const diff = currentX - this.startX;
    
    // Calculate custom translate
    const slideWidth = this.slides[0].getBoundingClientRect().width;
    const gap = this.currentParams.spaceBetween || 0;
    const baseTranslate = -this.currentIndex * (slideWidth + gap);
    
    this.currentTranslate = baseTranslate + diff;
    this.wrapper.style.transform = `translateX(${this.currentTranslate}px)`;
  }

  dragEnd() {
    if (!this.isDragging) return;
    this.isDragging = false;
    this.wrapper.style.transition = `transform var(--duration-normal, 300ms) var(--easing-default, ease)`;
    
    const diff = this.currentTranslate - this.prevTranslate;
    const threshold = 50;

    if (diff < -threshold) {
      this.slideNext();
    } else if (diff > threshold) {
      this.slidePrev();
    } else {
      this.slideTo(this.currentIndex);
    }
  }

  update() {
    const slideWidth = this.slides[0].getBoundingClientRect().width;
    const gap = this.currentParams.spaceBetween || 0;
    this.currentTranslate = -this.currentIndex * (slideWidth + gap);
    this.prevTranslate = this.currentTranslate;
    this.wrapper.style.transform = `translateX(${this.currentTranslate}px)`;

    // Update active slide class
    this.slides.forEach((slide, i) => {
      slide.classList.toggle('swiper-slide-active', i === this.currentIndex);
    });

    // Update pagination bullets
    if (this.paginationContainer) {
      const bullets = this.paginationContainer.querySelectorAll('.swiper-pagination-bullet');
      bullets.forEach((bullet, i) => {
        bullet.classList.toggle('swiper-pagination-bullet-active', i === this.currentIndex);
      });
    }

    // Update Navigation buttons disabled state
    if (!this.currentParams.loop) {
      const perView = this.currentParams.slidesPerView || 1;
      if (this.prevButton) {
        this.prevButton.classList.toggle('swiper-button-disabled', this.currentIndex === 0);
      }
      if (this.nextButton) {
        this.nextButton.classList.toggle('swiper-button-disabled', this.currentIndex >= this.slides.length - perView);
      }
    }
  }

  slideTo(index) {
    const maxIndex = this.slides.length - 1;
    this.currentIndex = Math.max(0, Math.min(index, maxIndex));
    this.update();
  }

  slideNext() {
    const perView = this.currentParams.slidesPerView || 1;
    if (this.currentIndex >= this.slides.length - perView) {
      if (this.currentParams.loop) {
        this.slideTo(0);
      }
    } else {
      this.slideTo(this.currentIndex + 1);
    }
  }

  slidePrev() {
    if (this.currentIndex === 0) {
      if (this.currentParams.loop) {
        const perView = this.currentParams.slidesPerView || 1;
        this.slideTo(this.slides.length - perView);
      }
    } else {
      this.slideTo(this.currentIndex - 1);
    }
  }
}

window.Swiper = Swiper;
